CREATE TABLE IF NOT EXISTS waitlist (\n  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),\n  email text NOT NULL UNIQUE,\n  submitted_at timestamptz DEFAULT now(),\n  source text DEFAULT 'direct'\n);\n\nCREATE TABLE IF NOT EXISTS users (\n  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),\n  email text NOT NULL UNIQUE,\n  password_hash text NOT NULL,\n  display_name text,\n  email_verified boolean DEFAULT false,\n  verification_token text,\n  created_at timestamptz DEFAULT now()\n);\n\nCREATE TABLE IF NOT EXISTS sessions (\n  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),\n  user_id uuid NOT NULL REFERENCES users(id) ON DELETE CASCADE,\n  token text NOT NULL UNIQUE,\n  created_at timestamptz DEFAULT now()\n);\n\nCREATE TABLE IF NOT EXISTS subscriptions (\n  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),\n  user_id uuid NOT NULL UNIQUE REFERENCES users(id) ON DELETE CASCADE,\n  paddle_customer_id text,\n  status text DEFAULT 'free',\n  price_id text,\n  current_period_end timestamptz,\n  created_at timestamptz DEFAULT now(),\n  updated_at timestamptz DEFAULT now()\n);\n\nALTER TABLE waitlist ENABLE ROW LEVEL SECURITY;\nALTER TABLE users ENABLE ROW LEVEL SECURITY;\nALTER TABLE sessions ENABLE ROW LEVEL SECURITY;\nALTER TABLE subscriptions ENABLE ROW LEVEL SECURITY;\n\nCREATE POLICY \"Allow service role all on waitlist\" ON waitlist\n  FOR ALL USING (auth.role() = 'service_role');\n\nCREATE POLICY \"Allow service role all on users\" ON users\n  FOR ALL USING (auth.role() = 'service_role');\n\nCREATE POLICY \"Allow service role all on sessions\" ON sessions\n  FOR ALL USING (auth.role() = 'service_role');\n\nCREATE POLICY \"Allow service role all on subscriptions\" ON subscriptions\n  FOR ALL USING (auth.role() = 'service_role');\n"